PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "is_admin" tinyint(1) not null default '0');
CREATE TABLE IF NOT EXISTS "halls" ("id" integer primary key autoincrement not null, "name" varchar not null, "rows" integer not null default '8', "seats_per_row" integer not null default '10', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "movies" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text not null, "poster" varchar, "duration" integer not null, "trailer_url" varchar, "release_date" date not null, "age_rating" varchar not null default '12+', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "bookings" ("id" integer primary key autoincrement not null, "user_id" integer not null, "movie_session_id" integer not null, "selected_seats" text not null, "total_price" numeric not null, "status" varchar check ("status" in ('pending', 'paid', 'cancelled')) not null default 'pending', "qr_code" varchar, "paid_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("movie_session_id") references "movie_sessions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "movie_sessions" ("id" integer primary key autoincrement not null, "movie_id" integer not null, "hall_id" integer not null, "start_time" datetime not null, "end_time" datetime not null, "price" numeric not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("movie_id") references "movies"("id") on delete cascade, foreign key("hall_id") references "halls"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE TRIGGER trg_deactivate_expired_session
AFTER UPDATE ON movie_sessions
BEGIN
    UPDATE movie_sessions
    SET is_active = 0
    WHERE datetime(end_time) < datetime('now') AND is_active = 1;
END;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
PRAGMA writable_schema=OFF;
COMMIT;
